function drawContour(){var e=document.getElementById("contour");if(e){var t=e.parentElement.getBoundingClientRect(),n=window.devicePixelRatio||1;e.width=t.width*n,e.height=t.height*n;var o=e.getContext("2d");o.setTransform(n,0,0,n,0,0),o.clearRect(0,0,t.width,t.height);var i=getComputedStyle(document.documentElement).getPropertyValue("--accent").trim()||"#3f6a4f";o.strokeStyle=hexToRgba(i,.35),o.lineWidth=1;for(var r=t.width,a=t.height,d=0;d<9;d++){var u=a/10*(d+1);o.beginPath();for(var c=0;c<=r;c+=6){var s=u+Math.sin(.006*c+.9*d)*(.05*a)+Math.sin(.017*c+1.7*d)*(.025*a);0===c?o.moveTo(c,s):o.lineTo(c,s)}o.stroke()}}}function hexToRgba(e,t){return e=e.replace("#",""),"rgba("+parseInt(e.substring(0,2),16)+","+parseInt(e.substring(2,4),16)+","+parseInt(e.substring(4,6),16)+","+t+")"}var contourResizeTimer;document.addEventListener("DOMContentLoaded",function(){var e=document.getElementById("preloader");e&&setTimeout(function(){e.style.opacity="0",setTimeout(function(){e.remove()},400)},300),drawContour(),window.AOS&&AOS.init({disable:"mobile",offset:150,duration:800,easing:"ease-out-cubic",delay:50,once:!0})}),window.addEventListener("resize",function(){clearTimeout(contourResizeTimer),contourResizeTimer=setTimeout(drawContour,200)}),window.matchMedia&&window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change",drawContour);